// lib/db.js
import { cacheTag } from 'next/cache';

/**
 * @typedef {{
 *   id: number;
 *   sku: string;
 *   name: string;
 *   price: number;
 *   inventory: number;
 *   availability: string;
 *   syncedAt?: string;
 * }} Product
 */

/** @type {Product[]} */
let products = [
  { id: 1, sku: 'LAP-001', name: 'Laptop', price: 999, inventory: 18, availability: 'In stock' },
  { id: 2, sku: 'PHN-001', name: 'Phone', price: 699, inventory: 42, availability: 'In stock' },
  { id: 3, sku: 'TAB-001', name: 'Tablet', price: 499, inventory: 0, availability: 'Backorder' },
  { id: 4, sku: 'HDP-001', name: 'Headphones', price: 199, inventory: 75, availability: 'In stock' },
  { id: 5, sku: 'WTC-001', name: 'Watch', price: 299, inventory: 11, availability: 'Limited stock' }
];

function randomDelta(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

/** @returns {Promise<Product[]>} */
export async function getAllProducts() {
  'use cache';
  cacheTag('products');

  await new Promise((resolve) => setTimeout(resolve, 100));

  return products;
}

export async function syncLatestCatalog() {
  await new Promise((resolve) => setTimeout(resolve, 1500));

  products = products.map((product, index) => {
    const inventory = Math.max(0, product.inventory + randomDelta(-8, 12));
    const availability = inventory === 0 ? 'Out of stock' : inventory < 10 ? 'Limited stock' : 'In stock';

    return {
      ...product,
      price: product.price + randomDelta(-25, 40),
      inventory,
      availability,
      syncedAt: new Date(Date.now() + index).toISOString()
    };
  });
}

